INSERT INTO `sys_settings` (`key`, `value`, `group`, `created_at`, `updated_at`) VALUES
('profil_bidang', '[{\"id\":\"sekretariat\",\"title\":\"Sekretariat\",\"subtitle\":\"Bagian Umum\",\"icon\":\"fa-folder-open\",\"badge\":\"Bagian Umum\",\"color\":\"#71717a\",\"description\":\"Sekretariat mempunyai tugas memberikan pelayanan administratif dan koordinasi pelaksanaan tugas sub bagian di lingkungan Badan Kesbangpol Kabupaten Sinjai.\",\"sub_units\":[\"Sub Bagian Kepegawaian & Umum\",\"Sub Bagian Keuangan & Program\"]},{\"id\":\"ideologi\",\"title\":\"Ideologi & Wasbang\",\"subtitle\":\"Fokus Kebangsaan\",\"icon\":\"fa-brain\",\"badge\":\"Fokus Kebangsaan\",\"color\":\"#e11d48\",\"description\":\"Bidang Ideologi, Wawasan Kebangsaan dan Karakter Bangsa melaksanakan perumusan kebijakan teknis, pembinaan, koordinasi, dan fasilitasi pembumian ideologi Pancasila serta wawasan kebangsaan bela negara.\",\"sub_units\":[\"Pendidikan Bela Negara\",\"Nilai Pancasila & Karakter Bangsa\"]},{\"id\":\"poldagri\",\"title\":\"Poldagri & Ormas\",\"subtitle\":\"Fokus Kemasyarakatan\",\"icon\":\"fa-users-rectangle\",\"badge\":\"Fokus Kemasyarakatan\",\"color\":\"#be123c\",\"description\":\"Bidang Politik Dalam Negeri dan Organisasi Kemasyarakatan mempunyai tugas merumuskan dan melaksanakan kebijakan teknis di bidang budaya demokrasi, pendidikan politik, pendaftaran lembaga, pembinaan dan pengawasan ormas.\",\"sub_units\":[\"Pendaftaran Ormas & LSM\",\"Sosialisasi Pemilu & Politik Daerah\"]},{\"id\":\"ekososbud\",\"title\":\"Ekososbud & Agama\",\"subtitle\":\"Fokus Ketahanan Sosial\",\"icon\":\"fa-shield-halved\",\"badge\":\"Fokus Ketahanan Sosial\",\"color\":\"#f59e0b\",\"description\":\"Bidang Ketahanan Ekonomi, Sosial, Budaya dan Agama melaksanakan fasilitasi kerukunan umat beragama (FKUB), pemantauan kerawanan sosial ekonomi, pencegahan konflik SARA, aliran sesat, serta kewaspadaan dini daerah.\",\"sub_units\":[\"Kerukunan Antar Umat Beragama\",\"Pengawasan Aliran Kepercayaan Daerah\"]}]', 'profil', '2026-06-15 07:06:42', '2026-06-15 07:14:10'),
('profil_misi', '[\"Meningkatkan pengamalan nilai-nilai Pancasila dan Wawasan Kebangsaan guna memperkokoh jati diri bangsa.\",\"Mewujudkan iklim politik dalam negeri yang demokratis, kondusif, aman, dan tertib.\",\"Meningkatkan kerukunan hidup antarumat beragama dan ketahanan sosial kemasyarakatan dari potensi konflik.\",\"Meningkatkan sinergitas pengawasan dan kewaspadaan dini daerah terhadap ancaman, tantangan, hambatan, dan gangguan.\"]', 'profil', '2026-06-15 07:06:42', '2026-06-15 07:14:10'),
('profil_visi', 'Terwujudnya Masyarakat Kabupaten Sinjai yang Damai, Demokratis, Berkarakter Bangsa dan Harmonis Berlandaskan Nilai Keagamaan dan Budaya Lokal.', 'profil', '2026-06-15 07:06:42', '2026-06-15 07:14:10'),
('struktur_organisasi', '[{\"id\":\"kaban\",\"role\":\"Kepala Badan\",\"name\":\"Drs. MUH. AKBAR JUHAMRAN, AP.MH\",\"nip\":\"NIP. 197401121994121001\",\"photo\":\"default_kaban.webp\",\"category\":\"pimpinan\"},{\"id\":\"sekretaris\",\"role\":\"Sekretaris\",\"name\":\"ADHAYANTI, S.STP.\",\"nip\":\"NIP. 197711211996122001\",\"photo\":\"foto_sekretaris_1782264394.webp\",\"category\":\"pimpinan\"},{\"id\":\"kasubbag_umum\",\"role\":\"Kasubbag Kepegawaian & Umum\",\"name\":\"BAKRI, S.Sos.\",\"nip\":\"NIP. 197403072007011016\",\"photo\":\"foto_kasubbag_umum_1782264425.webp\",\"category\":\"sekretariat\"},{\"id\":\"kasubbag_keuangan\",\"role\":\"Kasubbag Keuangan & Program\",\"name\":\"NURBAETI, SE.\",\"nip\":\"NIP. 198201232008012014\",\"photo\":\"default_kasubbag_keuangan.webp\",\"category\":\"sekretariat\"},{\"id\":\"staf_sekretariat_satmia_dewi_95\",\"role\":\"Penelaah teknis kebijakan\",\"name\":\"SATMIA DEWI.\",\"nip\":\"NIP. 198401012010012048\",\"photo\":\"default_staff_sekretariat_1.webp\",\"category\":\"sekretariat\"},{\"id\":\"staf_sekretariat_muhammad_reza_22\",\"role\":\"Bendahara \\/ Penelaah teknis kebijakan\",\"name\":\"MUHAMMAD REZA\",\"nip\":\"NIP. 199101132022031005\",\"photo\":\"foto_staf_sekretariat_muhammad_reza_22_1782264449.webp\",\"category\":\"sekretariat\"},{\"id\":\"staf_sekretariat_nurmansyah_76\",\"role\":\"Penelaah teknis kebijakan\",\"name\":\"NURMANSYAH\",\"nip\":\"NIP. 199004212022031005\",\"photo\":\"default_staff_sekretariat_2.webp\",\"category\":\"sekretariat\"},{\"id\":\"kabid_ideologi\",\"role\":\"Kabid Ideologi & Wasbang\",\"name\":\"MUHAYAR MATTOREANG, SE.\",\"nip\":\"NIP. 197805042008011026\",\"photo\":\"default_kabid_ideologi.webp\",\"category\":\"ideologi\"},{\"id\":\"staf_ideologi_nurbaya,_se_63\",\"role\":\"Analis Kebijakan Ahli Muda\",\"name\":\"NURBAYA, S.E.\",\"nip\":\"NIP. 197506232003122008\",\"photo\":\"default_staff_ideologi_1.webp\",\"category\":\"ideologi\"},{\"id\":\"staf_ideologi_azhar_pasahi,_ssos_65\",\"role\":\"A