('titik_kerawanan', '[]', 'gis', NULL, '2026-06-22 01:28:53'),
('video_edukasi', '[{\"id\":\"video_1\",\"title\":\"Pendidikan Wawasan Kebangsaan Bagi Pemuda\",\"category\":\"Wawasan Kebangsaan\",\"description\":\"Pembinaan karakter pancasila dan integrasi bangsa bagi kalangan remaja dan pelajar daerah.\",\"youtube_id\":\"dQw4w9WgXcQ\",\"duration\":\"5:12\",\"source\":\"Badan Kesbangpol Sinjai\"},{\"id\":\"video_2\",\"title\":\"Bela Negara: Dimulai Dari Kita\",\"category\":\"Wawasan Kebangsaan\",\"description\":\"Dengan konsistensi, langkah kecil ini bisa membawa perubahan besar. Mulai dari hal kecil, karena setiap langkah kecil bisa membawa perubahan besar!\",\"youtube_id\":\"j3pyfyZJEPI\",\"duration\":\"03.00\",\"source\":\"Kemhan RI\"},{\"id\":\"video_3\",\"title\":\"Sinjai: Bumi Panritta kita\",\"category\":\"Sosial Budaya\",\"description\":\"Hari Jadi Kabupaten Sinjai diperingati setiap tanggal 27 Februari. Tanggal ini menjadi momentum penting bagi masyarakat untuk mengenang sejarah terbentuknya pemerintahan dan perjalanan panjang daerah yang kini dikenal sebagai Kabupaten Sinjai di Provinsi Sulawesi Selatan.\",\"youtube_id\":\"vOsExjckwK8\",\"duration\":\"06.49\",\"source\":\"Sinjai Tv\"},{\"id\":\"video_1782287010_494\",\"title\":\"Foto\",\"type\":\"dokumentasi\",\"youtube_id\":\"\",\"image_path\":\"doc_1782287005.webp\",\"image_gallery\":[\"doc_gallery_1782287006_477.webp\",\"doc_gallery_1782287006_969.webp\",\"doc_gallery_1782287007_753.webp\",\"doc_gallery_1782287008_106.webp\",\"doc_gallery_1782287008_337.webp\",\"doc_gallery_1782287009_978.webp\"],\"category\":\"Umum\",\"duration\":\"-\",\"source\":\"Kesbangpol Sinjai\",\"description\":\"ini foto dokumentasi muka\"}]', 'informasi', NULL, '2026-06-24 07:43:30');

